module adder_32bit(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

    wire [32:0] carry;
    assign carry[0] = 0;

    genvar i;
    generate
        for (i = 1; i < 33; i = i + 1) begin
            wire p, g;
            assign p = A[i] ^ B[i];
            assign g = A[i] & B[i];
            assign carry[i] = g | (p & carry[i-1]);
            assign S[i] = p ^ carry[i-1];
        end
    endgenerate

    assign C32 = carry[32];

endmodule
